import{_ as a,o as t,c as i,ag as r}from"./chunks/framework._658-eYr.js";const o="/CRAFT/assets/ideas-generate.Cg6Xi6SH.png",p=JSON.parse('{"title":"Ideas","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ideas.md","filePath":"guide/ideas.md"}'),n={name:"guide/ideas.md"};function s(l,e,d,c,h,g){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="ideas" tabindex="-1">Ideas <a class="header-anchor" href="#ideas" aria-label="Permalink to &quot;Ideas&quot;">​</a></h1><p>The Ideas panel is where content starts. Generate ideas with AI, capture inspiration from YouTube, or add your own manually.</p><h2 id="creating-ideas" tabindex="-1">Creating Ideas <a class="header-anchor" href="#creating-ideas" aria-label="Permalink to &quot;Creating Ideas&quot;">​</a></h2><h3 id="manual" tabindex="-1">Manual <a class="header-anchor" href="#manual" aria-label="Permalink to &quot;Manual&quot;">​</a></h3><ol><li>Click the <strong>expand/add</strong> area at the top of the Ideas panel</li><li>Enter a <strong>Title</strong>, <strong>Hook</strong> (what grabs the viewer), and <strong>Angle</strong> (your unique take)</li><li>Select <strong>Short</strong> or <strong>Long</strong> format</li><li>Add tags and click <strong>Save</strong></li></ol><h3 id="ai-generate" tabindex="-1">AI Generate <a class="header-anchor" href="#ai-generate" aria-label="Permalink to &quot;AI Generate&quot;">​</a></h3><ol><li>Click <strong>Generate Ideas</strong> (or the AI button on mobile)</li><li>Optionally add context (e.g., &quot;trending topic: James Webb images&quot;)</li><li>Select your AI model</li><li>Click <strong>Generate 5 Ideas</strong></li></ol><p>The AI generates ideas in your channel&#39;s character voice, with titles, hooks, angles, and tags.</p><p><img src="'+o+'" alt="AI Generate Ideas"></p><h3 id="from-discover" tabindex="-1">From Discover <a class="header-anchor" href="#from-discover" aria-label="Permalink to &quot;From Discover&quot;">​</a></h3><p>When researching YouTube videos in the <a href="/CRAFT/guide/discover.html">Discover</a> panel, click <strong>Save as Idea</strong> on any video. The idea captures the video&#39;s metadata (views, duration, description) as enrichment data.</p><h2 id="managing-ideas" tabindex="-1">Managing Ideas <a class="header-anchor" href="#managing-ideas" aria-label="Permalink to &quot;Managing Ideas&quot;">​</a></h2><h3 id="search-filter" tabindex="-1">Search &amp; Filter <a class="header-anchor" href="#search-filter" aria-label="Permalink to &quot;Search &amp; Filter&quot;">​</a></h3><ul><li><strong>Search</strong> — filter by title, hook, angle, or tags</li><li><strong>Type toggle</strong> — All / Short / Long</li><li><strong>Sort</strong> — Newest, Oldest, Title</li><li><strong>Hide converted</strong> — toggle to show/hide ideas already converted to scripts</li></ul><h3 id="editing" tabindex="-1">Editing <a class="header-anchor" href="#editing" aria-label="Permalink to &quot;Editing&quot;">​</a></h3><p>Click an idea to expand it. Edit title, hook, angle, tags, and type inline.</p><h3 id="deleting" tabindex="-1">Deleting <a class="header-anchor" href="#deleting" aria-label="Permalink to &quot;Deleting&quot;">​</a></h3><ul><li><strong>Web</strong> — multi-select with checkboxes, then bulk delete</li><li><strong>Mobile</strong> — long-press an idea card for delete confirmation</li></ul><h2 id="convert-to-script" tabindex="-1">Convert to Script <a class="header-anchor" href="#convert-to-script" aria-label="Permalink to &quot;Convert to Script&quot;">​</a></h2><p>When an idea is ready to develop:</p><ol><li>Expand the idea</li><li>Click <strong>Convert to Script</strong></li><li>A new script is created with the idea&#39;s title, hook, angle, and any enrichment data (transcripts, stats from Discover)</li><li>The idea is marked as converted and hidden by default</li></ol><div class="info custom-block"><p class="custom-block-title">Source Tracking</p><p>Every idea tracks its source: <code>manual</code>, <code>ai</code>, or <code>discover</code>. Ideas from Discover carry metadata through to scripts for reference.</p></div>',22)])])}const m=a(n,[["render",s]]);export{p as __pageData,m as default};
